  ('real-estate-moex-00688', 'real-estate', 'real-estate-moex-108-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依土地稅法規定，關於地價稅之納稅義務人，下列何項敘述錯誤？', '["信託土地，於信託關係存續中，為受託人", "設有典權土地，為出典人", "承領土地，為承領人", "承墾土地，為耕作權人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "eb18e2baa04f", "answer_pdf_sha1": "718d3b7e2330", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
